    for (int i = 0; i <n1; ++i)
    {
        left[i]=arr[i+l];
    }
    for (int i = 0; i < n2; ++i)
    {
        right[i]=arr[i+mid+1];
    }

    ll i=0,j=0,k=l;
    while(i<n1 && j<n2){
