        return parent[v] = get(parent[v]);  // Path compression
    }

    // Union by size
    void union_set(ll a, ll b) {
        a = get(a);
        b = get(b);
        if (a != b) {
            if (size[a] < size[b])
                swap(a, b);
            parent[b] = a;
            size[a] += size[b];
        }
    }
};

