ll merge(vl &arr,ll l,ll mid,ll r){
    ll cnt=0;
    ll n1=mid-l+1,n2=r-mid;
    vl left(n1),right(n2);
    for (int i = 0; i <n1; ++i)
    {
        left[i]=arr[i+l];
    }
    for (int i = 0; i < n2; ++i)
    {
        right[i]=arr[i+mid+1];
    }

    ll i=0,j=0,k=l;
    while(i<n1 && j<n2){
        if(left[i]>right[j]){
            cnt+= n1-i;
            arr[k]=right[j];
            j++;
        }
        else{
            arr[k]=left[i];
            i++;
        }
        k++;
    }

    while(i<n1){
        arr[k++]=left[i++];
    }

    while(j<n2){
        arr[k++]=right[j++];
    }

    return cnt;
}

